#nullable enable // autogenerated

using MVZ2.GameContent.Enemies;
using MVZ2.Vanilla.Carts;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;

using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;

using Tools;

namespace MVZ2.GameContent.Carts
{
    [AutoEntityBehaviourDefinition(VanillaCartNames.corpseCart)]
    public class CorpseCart : CartBehaviour
    {
        public CorpseCart(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (!entity.IsCartTriggered())
                return;
            var timer = entity.GetProperty<FrameTimer>(PROP_RELEASE_ZOMBIE_TIMER);
            if (timer == null)
            {
                timer = TimerHelper.NewSecondTimer(RELEASE_INTERVAL_SECONDS);
                entity.SetProperty<FrameTimer>(PROP_RELEASE_ZOMBIE_TIMER, timer);
            }
            if (timer.RunToExpired())
            {
                entity.SpawnWithParams(VanillaEnemyID.zombie, entity.Position);
                timer.Reset();
            }
        }
        public const float RELEASE_INTERVAL_SECONDS = 0.5f;
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_RELEASE_ZOMBIE_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("release_zombie_timer");
    }
}